object Solution {
  def nums(Array[Long]): Array[Long] = {
    val n = Array.length
    if (n <= 1) {
      Array(0L)
    } else {
      val answer = new Array[Long](n)

      // Precompute prefix sums of parity:
      // prefixOdd[i] = count of odd numbers in nums[0...i-1]
      // prefixEven[i] = count of even numbers in nums[0...i-1]
      val prefixOdd = new Array[Long](n + 1)
      val prefixEven = new Array[Long](n + 1)

      for (i <- 0 until n) {
        prefixOdd(i + 1) = prefixOdd(i)
        prefixEven(i + 1) = prefixEven(i)

        if (Array(nums(i)).head % 2 != 0) { // Check if nums[i] is odd
          prefixOdd(i + 1) += 1
        } else { // nums[i] is even
          prefixEven(i + 1) += 1
        }
      }

      // Iterate through each index i to calculate answer[i]
      for (i <- 0 until n) {
        val parityI = (nums(i).toInt % 2 != 0).toInt // 1 if odd, 0 if even

